public class BoundedList<T> {
    private List<T> items = new ArrayList<>();
    private int maxSize;

    public BoundedList(int maxSize) {
        this.maxSize = maxSize;
    }

    public boolean add(T item) {
        if (items.size() >= maxSize) return false;
        items.add(item);
        return true;
    }

    public List<T> getItems() { return Collections.unmodifiableList(items); }
    public int size() { return items.size(); }
}

public static <T> Optional<T> getLast(List<T> list) {
    if (list == null || list.isEmpty()) return Optional.empty();
    return Optional.of(list.get(list.size() - 1));
}

public interface Rankable {
    int getRankValue();
}

public class Student implements Rankable {
    private String name;
    private double gpa;
    @Override public int getRankValue() { return (int)(gpa * 100); }
}

public class Product implements Rankable {
    private String name;
    private int salesCount;
    @Override public int getRankValue() { return salesCount; }
}

// Sort either type using the same logic:
List<Rankable> items = new ArrayList<>();
items.sort(Comparator.comparingInt(Rankable::getRankValue));

public static <T> List<T> filterBy(List<T> items, Predicate<T> rule) {
    return items.stream()
        .filter(rule)
        .collect(Collectors.toList());
}

// Usage examples:
List<Integer> evens = filterBy(numbers, n -> n % 2 == 0);
List<String> shortNames = filterBy(names, name -> name.length() < 5);

